import { useLocation } from 'react-router-dom';

interface SEOProps {
  title: string;
  description: string;
  url?: string;
  image?: string;
  schema?: Record<string, any> | Record<string, any>[];
  article?: boolean;
}

export default function SEO({ 
  title, 
  description, 
  url, 
  image = 'https://fouriqtech.com/og-image.jpg',
  schema,
  article = false
}: SEOProps) {
  const location = useLocation();
  const baseUrl = 'https://fouriqtech.com';

  const path = location.pathname === '/' ? '' : location.pathname;
  const canonicalUrl = url || `${baseUrl}${path}`;

  // Ensure description is always present to prevent empty meta tags
  const metaDescription = description || "Leading global web design agency providing custom websites, software development, and expert SEO services to help your business grow.";

  const organizationSchema = {
    "@context": "https://schema.org",
    "@type": "Organization",
    "name": "Four IQ Tech",
    "url": baseUrl,
    "logo": "https://fouriqtech.com/4Q.png",
    "image": "https://fouriqtech.com/og-image.jpg",
    "description": metaDescription,
    "telephone": "+91 81403 71710",
    "contactPoint": [
      {
        "@type": "ContactPoint",
        "telephone": "+91 81403 71710",
        "contactType": "customer service"
      },
      {
        "@type": "ContactPoint",
        "telephone": "+91 97253 10310",
        "contactType": "sales"
      },
      {
        "@type": "ContactPoint",
        "telephone": "+91 88669 20015",
        "contactType": "technical support"
      }
    ],
    "sameAs": [
      "https://www.linkedin.com/company/fouriqtech",
      "https://twitter.com/fouriqtech"
    ]
  };

  const schemasToRender = schema 
    ? (Array.isArray(schema) ? [organizationSchema, ...schema] : [organizationSchema, schema])
    : [organizationSchema];

  return (
    <Helmet>
      <meta name="viewport" content="width=device-width, initial-scale=1.0" />
      <title>{title}</title>
      <meta name="description" content={metaDescription} />

      <link rel="canonical" href={canonicalUrl} />

      <meta property="og:type" content={article ? 'article' : 'website'} />
      <meta property="og:url" content={canonicalUrl} />
      <meta property="og:title" content={title} />
      <meta property="og:description" content={metaDescription} />
      <meta property="og:image" content={image} />

      <meta property="twitter:card" content="summary_large_image" />
      <meta property="twitter:url" content={canonicalUrl} />
      <meta property="twitter:title" content={title} />
      <meta property="twitter:description" content={metaDescription} />
      <meta property="twitter:image" content={image} />

      <script type="application/ld+json">
        {JSON.stringify(schemasToRender)}
      </script>
    </Helmet>
  );
}"}

